1.6}\n.section-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 12px;\n            font-weight: 500;\n            color: #0369a1;\n            letter-spacing: 2px;\n            text-transform: uppercase;\n            margin-bottom: 16px;\n            display: block;\n        }\n.series-section {\n            padding: 100px 24px;\n            background: #fff;\n        }\n.series-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n        }\n.series-header {\n            text-align: center;\n            margin-bottom: 64px;\n        }\n.series-header h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 40px;\n            font-weight: 700;\n            color: #000864;\n            margin-bottom: 16px;\n        }\n.series-header p {\n            font-size: 18px;\n            color: #5b6b80;\n            max-width: 650px;\n            margin: 0 auto;\n            line-height: 1.7;\n        }\n.series-timeline {\n            display: grid;\n            grid-template-columns: repeat(4, 1fr);\n            gap: 0;\n            position: relative;\n        }\n.series-timeline::before {\n            content: \'\';\n            position: absolute;\n            top: 32px;\n            left: 12.5%;\n            right: 12.5%;\n            height: 3px;\n            background: linear-gradient(90deg, #00AFF0, #22C55E, #F59E0B, #8B5CF6);\n            border-radius: 2px;\n            z-index: 0;\n        }\n.series-step {\n            text-align: center;\n            position: relative;\n            z-index: 1;\n            padding: 0 16px;\n        }\n.series-step-number {\n            width: 64px;\n            height: 64px;\n            border-radius: 50%;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            margin: 0 auto 20px;\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 22px;\n            font-weight: 700;\n            color: #fff;\n            position: relative;\n        }\n.series-step:nth-child(1) .series-step-number { background: linear-gradient(135deg, #00AFF0, #003CC8); }\n.series-step:nth-child(2) .series-step-number { background: linear-gradient(135deg, #22C55E, #16a34a); }\n.series-step:nth-child(3) .series-step-number { background: linear-gradient(135deg, #F59E0B, #d97706); }\n.series-step:nth-child(4) .series-step-number { background: linear-gradient(135deg, #8B5CF6, #7c3aed); }\n.series-step-number::after {\n            content: \'\';\n            position: absolute;\n            inset: -4px;\n            border-radius: 50%;\n            border: 2px solid rgba(255,255,255,0.3);\n        }\n.series-step:nth-child(1) .series-step-number::after { border-color: rgba(0, 175, 240, 0.3); }\n.series-step:nth-child(2) .series-step-number::after { border-color: rgba(34, 197, 94, 0.3); }\n.series-step:nth-child(3) .series-step-number::after { border-color: rgba(245, 158, 11, 0.3); }\n.series-step:nth-child(4) .series-step-number::after { border-color: rgba(139, 92, 246, 0.3); }\n.series-step-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            font-weight: 500;\n            color: #5b6b80;\n            letter-spacing: 1px;\n            text-transform: uppercase;\n            margin-bottom: 8px;\n            display: block;\n        }\n.series-step h3 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 18px;\n            font-weight: 600;\n            color: #000864;\n            margin-bottom: 12px;\n            line-height: 1.3;\n        }\n.series-step p {\n            font-size: 14px;\n            color: #5b6b80;\n            line-height: 1.6;\n        }\n.fade-in-section {\n            opacity: 0;\n            transform: translateY(30px);\n            transition: opacity 0.4s ease, transform 0.4s ease;\n        }\n.fade-in-section.is-visible {\n            opacity: 1;\n        