uppercase;\n            margin-bottom: 16px;\n            width: fit-content;\n        }\n.event-type-badge.seminar {\n            background: rgba(0, 175, 240, 0.12);\n            color: #0369a1;\n        }\n.event-type-badge.workshop {\n            background: rgba(34, 197, 94, 0.12);\n            color: #15803d;\n        }\n.event-type-badge.factory-visit {\n            background: rgba(245, 158, 11, 0.12);\n            color: #b45309;\n        }\n.event-type-badge.trade-show {\n            background: rgba(139, 92, 246, 0.12);\n            color: #7c3aed;\n        }\n.section-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 12px;\n            font-weight: 500;\n            color: #0369a1;\n            letter-spacing: 2px;\n            text-transform: uppercase;\n            margin-bottom: 16px;\n            display: block;\n        }\n.upcoming-card-border.seminar { background: #00AFF0; }\n.upcoming-card-border.workshop { background: #22C55E; }\n.upcoming-card-border.trade-show { background: #8B5CF6; }\n.upcoming-card-body .event-type-badge {\n            margin-bottom: 16px;\n        }\n.event-link {\n            display: inline-flex;\n            align-items: center;\n            gap: 6px;\n            color: #0369a1;\n            font-weight: 600;\n            font-size: 14px;\n            text-decoration: none;\n            transition: all 0.3s ease;\n        }\n.event-link:hover {\n            gap: 10px;\n        }\n.past-section {\n            padding: 100px 24px;\n            background: #F5F7FA;\n        }\n.past-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n        }\n.past-header {\n            text-align: center;\n            margin-bottom: 40px;\n        }\n.past-header h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 40px;\n            font-weight: 700;\n            color: #000864;\n            margin-bottom: 0;\n        }\n.filter-bar {\n            dis