0,175,240,0.3)}\n.event-cta-secondary{display:inline-flex!important;align-items:center!important;gap:8px!important;background:transparent!important;color:#00AFF0!important;padding:16px 24px!important;border-radius:12px!important;border:1px solid rgba(0,175,240,0.3)!important;font-weight:600!important;font-size:15px!important;text-decoration:none!important;width:fit-content!important;font-family:\'Noto Sans\',sans-serif!important;transition:all 0.3s ease!important}\n.event-cta-secondary:hover{background:rgba(0,175,240,0.08)!important;border-color:#00AFF0!important}\n.event-cta svg,.event-cta-secondary svg{flex-shrink:0}\n</style>\n    <div class="particle-ocean-host" data-particles style="position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;overflow:hidden;"></div>\n            <div class="featured-inner" style="position: relative; z-index: 2;">\n                <span class="featured-label">Featured Event</span>\n                <div class="featured-card">\n                    <div class="featured-image">\n                        <div class="fea">\n                            <div class="fea-month">Mar</div>\n                            <div class="fea-day">11</div>\n                            <div class="fea-year">2026</div>\n                            <div class="fea-divider"></div>\n                        </div>\n                        <div class="fea-meta">\n                            <div class="fea-meta-item">\n                                <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n                                10:00 – 18:00 (3 Days)\n                            </div>\n                            <div class="fea-meta-item">\n                                <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n                                BITEC Bangkok, EH 98 Hall\n                            </div>\n                        </div>\n                        <span class="urgency-badge" style="background:rgba(8,145,178,0.15);border-color:rgba(8,145,178,0.3);color:#0891b2;">\n                            <svg aria-hidden="true" width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n                            Booth I132, Open Entry\n                        </span>\n                    </div>\n                    <div class="featured-content">\n                        <span class="event-type-badge trade-show">Trade Show</span>\n                        <h2>Intelligent Asia Thailand 2026: DigiWin Smart Electronics Manufacturing</h2>\n                        <div class="event-meta">\n                            <div class="event-meta-item">\n                                <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n                                March 11–13, 2026 | 10:00 – 18:00\n                            </div>\n                            <div class="event-meta-item">\n                                <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n                                BITEC Bangkok, EH 98 Hall — Booth I132\n                            </div>\n                        </div>\n                        <p>DigiWin Thailand and Digihua Smart showcase e-Tax compliance, AI-powered smart manufacturing integration, and deep electronics industry solutions. Visit us at Booth I132.</p>\n                        <div class="featured-cta-row">\n                            <a href="/intelligent-asia-2026/" class="event-cta">Book a Meeting\n                                <svg aria-hidden="true" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n                            </a>\n                            <a href="/intelligent-asia-thailand-20260311/" class="event-cta-secondary">Read Day 1 Coverage\n                                <svg aria-hidden="true" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n                            </a>\n                        </div>\n                    </div>\n                </div>\n            </div>\n            <script>\n(function(){\n\'use strict\';\nvar rm=window.matchMedia(\'(prefers-reduced-motion: reduce)\').matches;\nvar PI2=Math.PI*2;\nvar BLUE=[0,175,240],CYAN=[0,230,255];\nvar PRESET={frontOpacity:0.30,backOpacity:0.04,frontRadius:4.5,backRadius:0.6,color:BLUE,colorAlt:CYAN,altRatio:0.12};\nfunction lerp(a,b,t){return a+(b-a)*t;}\n\nfunction DataOcean(section){\nthis.el=section;this.canvas=null;this.ctx=null;this.w=0;this.h=0;\nthis.dpr=Math.min(window.devicePixelRatio||1,2);this.visible=false;this.raf=null;this.time=0;this.resizeTimer=null;this.colors=null;\nthis.opts=PRESET;this._setup();this._buildColors();this._observe();\nif(!rm){this._loop();}else{this.visible=true;this._draw(0);}\n}\n\nDataOcean.prototype._setup=function(){\nvar c=document.createElement(\'canvas\');c.setAttribute(\'aria-hidden\',\'true\');\nc.style.cssText=\'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;\';\nthis.el.style.position=\'relative\';\nthis.el.style.overflow=\'hidden\';\nthis.el.insertBefore(c,this.el.firstChild);\nthis.canvas=c;this.ctx=c.getContext(\'2d\');this._resize();\nvar self=this;window.addEventListener(\'resize\',function(){clearTimeout(self.resizeTimer);self.resizeTimer=setTimeout(function(){self._resize();self._buildColors();},200);});\n};\n\nDataOcean.prototype._resize=function(){\n/* Use clientHeight — the CSS box size, not scroll or content height */\nthis.w=this.el.clientWidth;this.h=this.el.clientHeight;\nthis.canvas.width=this.w*this.dpr;this.canvas.height=this.h*this.dpr;\nthis.ctx.setTransform(this.dpr,0,0,this.dpr,0,0);\n};\n\nDataOcean.prototype._buildColors=function(){var cols=Math.min(65,Math.ceil(this.w/22)+4);var rows=35;this._cols=cols;this._rows=rows;var n=cols*rows;this.colors=new Array(n);var alt=this.opts.altRatio;for(var i=0;i<n;i++){this.colors[i]=Math.random()<alt?this.opts.colorAlt:this.opts.color;}};\nDataOcean.prototype._observe=function(){var self=this;if(\'IntersectionObserver\' in window){this._obs=new IntersectionObserver(function(e){self.visible=e[0].isIntersecting;},{rootMargin:\'150px 0px\'});this._obs.observe(this.el);}else{this.visible=true;}};\nDataOcean.prototype._loop=function(){var self=this;var last=0;(function tick(ts){self.raf=requestAnimationFrame(tick);if(!self.visible)return;if(ts-last<30)return;last=ts;self.time+=0.006;self._draw(self.time);})(0);};\n\nDataOcean.prototype._draw=function(t){\nvar ctx=this.ctx,w=this.w,h=this.h,opts=this.opts,cols=this._cols,rows=this._rows;\nctx.clearRect(0,0,w,h);\nvar ground=h+10,horizon=h*0.35,totalSpan=ground-horizon,idx=0;\nfor(var row=rows-1;row>=0;row--){\nvar depth=row/(rows-1),mappedDepth=Math.pow(depth,0.55),baseY=ground-mappedDepth*totalSpan;\nvar dotR=lerp(opts.frontRadius,opts.backRadius,depth),dotA=lerp(opts.frontOpacity,opts.backOpacity,depth);\nvar colSpacing=lerp(w/(cols-4),w/(cols+15),depth),rowShift=depth*w*0.12;\nvar waveScale=(1-depth*0.75),amp1=70*waveScale,amp2=25*waveScale;\nfor(var col=0;col<cols;col++){\nvar screenX=col*colSpacing-rowShift+colSpacing*0.5;\nif(screenX<-30||screenX>w+30){idx++;continue;}\nvar worldX=col*24,worldZ=row*18;\nvar wave=amp1*Math.sin(worldX*0.0065+worldZ*0.012+t*0.9);\nwave+=amp2*Math.sin(worldX*0.013-worldZ*0.008+t*0.55+1.8);\nvar screenY=baseY-wave;if(screenY<-15||screenY>h+15){idx++;continue;}\nvar c=this.colors[idx%this.colors.length];\nctx.beginPath();ctx.arc(screenX,screenY,dotR,0,PI2);\nctx.fillStyle=\'rgba(\'+c[0]+\',\'+c[1]+\',\'+c[2]+\',\'+dotA+\')\';ctx.fill();idx++;\n}}};\n\n/* Init: walk up from marker to .et_pb_section, insert canvas there */\nfunction init(){\nvar marker=document.querySelector(\'.particle-ocean-host\');\nif(!marker)return;\nvar section=marker.closest(\'.et_pb_section\');\nif(!section){section=marker.closest(\'.featured-section\');} /* HTML fallback */\nif(!section)return;\nmarker.remove(); /* clean up — canvas goes on section */\nnew DataOcean(section);\n}\n/* Delay to ensure Divi CSS has loaded and section is properly sized */\nif(document.readyState===\'complete\'){setTimeout(init,200);}\nelse{window.addEventListener(\'load\',function(){setTimeout(init,200);});}\n})();\n            </script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Upcoming"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Upcoming: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Upcoming: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="upc-inner" style="position: relative; z-index: 2;">\n                <div class="upc-header fade-in-section">\n                    <span class="section-label">Upcoming Events</span>\n                    <h2>What\'s Next</h2>\n                </div>\n                <div class="upc-empty">\n                    <p>New events are being planned. Follow us to stay updated.</p>\n                    <a href="/demo/" class="event-link">Get in Touch <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></a>\n                </div>\n            </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Series"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Series: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Series: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="series-inner" style="position: relative; z-index: 2;">\n                <div class="series-header fade-in-section">\n                    <span class="section-label">Recurring Campaign</span>\n                    <h2>Manufacturing Competitiveness Series</h2>\n                    <p>A monthly deep-dive into the challenges Thai manufacturers face -- and the tools that solve them.</p>\n                </div>\n                <div class="series-timeline fade-in-section">\n                    <div class="series-step">\n                        <div class="series-step-number">1</div>\n                        <span class="series-step-label">Month 1</span>\n                        <h3>BOI Compliance</h3>\n                        <p>Eliminate supplementary taxes through production-level reconciliation</p>\n                    </div>\n                    <div class="series-step">\n                        <div class="series-step-number">2</div>\n                        <span class="series-step-label">Month 2</span>\n                        <h3>Production Transparency</h3>\n                        <p>Replace paper reports with real-time shop floor visibility</p>\n                    </div>\n                    <div class="series-step">\n                        <div class="series-step-number">3</div>\n                        <span class="series-step-label">Month 3</span>\n                        <h3>Cash Flow Management</h3>\n                        <p>Connect production costs to financial planning in real-time</p>\n                    </div>\n                    <div class="series-step">\n                        <div class="series-step-number">4</div>\n                        <span class="series-step-label">Month 4</span>\n                        <h3>ERP Migration Options</h3>\n                        <p>What to do when your current ERP reaches end of life</p>\n                    </div>\n                </div>\n            </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Past"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Past: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Past: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dw-d-bg dw-d-bg--corner-br" style="opacity: 0.06;"></div>\n            <div class="past-inner" style="position: relative; z-index: 2;">\n                <div class="past-header fade-in-section">\n                    <span class="section-label">Past Events</span>\n                    <h2>What We\'ve Done</h2>\n                </div>\n                <div class="filter-bar fade-in-section">\n                    <button class="filter-tab active" data-filter="all">All</button>\n                    <button class="filter-tab" data-filter="seminar">Seminars</button>\n                    <button class="filter-tab" data-filter="workshop">Workshops</button>\n                    <button class="filter-tab" data-filter="factory-visit">Factory Visits</button>\n                    <button class="filter-tab" data-filter="trade-show">Trade Shows</button>\n                </div>\n                <div class="past-grid" id="past-events-grid">\n                    \n                    <div class="past-card fade-in-section" data-type="seminar">\n                        <span class="event-type-badge seminar">Seminar</span>\n                        <h3>ERP for Thai Manufacturing: What to Look For in 2026</h3>\n                        <span class="event-date">January 18, 2026</span>\n                        <a href="#" class="event-link">View Recap <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></a>\n                    </div>\n                    \n                    <div class="past-card fade-in-section" data-type="workshop">\n                        <span class="event-type-badge workshop">Workshop</span>\n                        <h3>Warehouse Efficiency: WMS Basics for Factory Operations</h3>\n                        <span class="event-date">December 12, 2025</span>\n                        <a href="#" class="event-link">View Recap <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></a>\n                    </div>\n                    \n                    <div class="past-card fade-in-section" data-type="trade-show">\n                        <span class="event-type-badge trade-show">Trade Show</span>\n                        <h3>Manufacturing Expo Thailand 2025 Recap</h3>\n                        <span class="event-date">November 15-17, 2025</span>\n                        <a href="#" class="event-link">View Recap <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></a>\n                    </div>\n                </div>\n            </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cta"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cta: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cta: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dw-d-bg dw-d-bg--left" style="opacity: 0.12;"></div>\n            <div class="news-cta-inner fade-in-section" style="position: relative; z-index: 3;">\n                <h2>Don\'t Miss the Next Event</h2>\n                <p>Join 500+ Thai manufacturing professionals who stay informed about industry trends, compliance updates, and technology opportunities.</p>\n                <form class="cta-form" onsubmit="event.preventDefault();">\n                    <label for="subscribe-email" class="sr-only">Email address</label>\n                    <input type="email" id="cta-email" class="cta-input" placeholder="Enter your email address" required>\n                    <button type="submit" class="cta-btn">Subscribe</button>\n                </form>\n                <a href="/demo/" class="cta-secondary-link">Or Let\'s Talk Directly <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></a>\n            </div>\n            <script>\n            (function(){\n              /* ── Fade-in scroll observer ── */\n              var els = document.querySelectorAll(\'.fade-in-section\');\n              if (!window.matchMedia(\'(prefers-reduced-motion: reduce)\').matches && els.length) {\n                var io = new IntersectionObserver(function(entries){\n                  entries.forEach(function(e){\n                    if(e.isIntersecting){e.target.classList.add(\'is-visible\');io.unobserve(e.target);}\n                  });\n                }, {threshold:0.15});\n                els.forEach(function(el){io.observe(el);});\n              } else {\n                els.forEach(function(el){el.classList.add(\'is-visible\');});\n              }\n              /* ── Past Events filter tabs ── */\n              var tabs = document.querySelectorAll(\'.filter-tab\');\n              var cards = document.querySelectorAll(\'.past-card\');\n              tabs.forEach(function(tab){\n                tab.addEventListener(\'click\', function(){\n                  tabs.forEach(function(t){t.classList.remove(\'active\');});\n                  tab.classList.add(\'active\');\n                  var f = tab.getAttribute(\'data-filter\');\n                  cards.forEach(function(c){\n                    if(f===\'all\'||c.getAttribute(\'data-type\')===f){\n                      c.style.display=\'\';\n                      c.classList.remove(\'is-visible\');\n                      setTimeout(function(){c.classList.add(\'is-visible\');},50);\n                    } else {c.style.display=\'none\';}\n                  });\n                });\n              });\n            })();\n            </script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100571;

