INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100571, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === HERO (S1) === */\n/* Divi 5 section boilerplate (font-smoothing, p padding, heading resets) */\n.hero-section{position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.hero-section p{padding-bottom:0;line-height:1.6}\n.hero-section h2,.hero-section h3,.hero-section h4{margin:0;padding:0;line-height:1.6}\n/* .news-hero bg/pseudo handled by section-level :has() overrides below */\n.hero-illustration {\n            position: absolute;\n            bottom: 0;\n            right: 0;\n            width: 600px;\n            height: 100%;\n            pointer-events: none;\n            overflow: hidden;\n        }\n.hero-illustration svg {\n            position: absolute;\n            bottom: -20px;\n            right: -40px;\n            width: 560px;\n            height: 480px;\n            opacity: 0.12;\n        }\n.hero-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            text-align: center;\n            position: relative;\n            z-index: 1;\n        }\n.hero-badge {\n            display: inline-flex;\n            align-items: center;\n            gap: 8px;\n            background: rgba(0, 175, 240, 0.2);\n            border: 1px solid rgba(0, 175, 240, 0.3);\n            padding: 8px 20px;\n            border-radius: 50px;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 13px;\n            font-weight: 500;\n            color: #7EC8F2;\n            letter-spacing: 1.5px;\n            text-transform: uppercase;\n            margin-bottom: 24px;\n        }\n.hero-inner h1 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: clamp(32px, 5vw, 52px);\n            font-weight: 700;\n            color: #fff;\n            line-height: 1.15;\n            margin-bottom: 20px;\n            max-width: 800px;\n            margin-left: auto;\n            margin-right: auto;\n        }\n.hero-inner h1 span {\n            color: #00AFF0;\n        }\n.hero-subtitle {\n            font-size: 18px;\n            color: rgba(255,255,255,0.85);\n            line-height: 1.7;\n            max-width: 680px;\n            margin: 0 auto 48px;\n        }\n.hero-stats {\n            display: grid;\n            grid-template-columns: repeat(3, 1fr);\n            gap: 32px;\n            max-width: 700px;\n            margin: 0 auto;\n            padding-top: 40px;\n            border-top: 1px solid rgba(255,255,255,0.1);\n        }\n.hero-stat {\n            text-align: center;\n        }\n.hero-stat-value {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 42px;\n            font-weight: 700;\n            color: #00AFF0;\n            line-height: 1;\n            margin-bottom: 8px;\n        }\n.hero-stat-label {\n            font-size: 14px;\n            color: rgba(255,255,255,0.75);\n            line-height: 1.4;\n        }\n@media (max-width: 1024px) {\n.hero-illustration {\n                width: 400px;\n                opacity: 0.7;\n            }\n}\n@media (max-width: 640px) {\n/* responsive padding handled by section-level :has() */\n.hero-illustration {\n                display: none;\n            }\n.hero-inner h1 {\n                font-size: 28px;\n            }\n.hero-stats {\n                grid-template-columns: repeat(3, 1fr);\n                gap: 16px;\n            }\n.hero-stat-value {\n                font-size: 32px;\n            }\n}\n\n/* Super D now rendered via ::before on section (see below) — no div needed */\n\n.et_pb_section .hero-badge {\n            line-height: 20.8px !important;\n        \n            padding-top: 8px;\n\n            padding-bottom: 8px;\n\n            -webkit-font-smoothing: auto !important;\n}\n\n.et_pb_section .hero-stat-label {\n            line-height: 19.6px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.et_pb_section .hero-stat-value {\n            line-height: 42px !important;\n        \n            color: rgb(0, 175, 240) !important;\n\n            margin-bottom: 8px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n\n/* Divi section-level overrides */\n.et_pb_section:has(.hero-inner) {\n  background: linear-gradient(165deg, #0f1419 0%, #1a2632 40%, #000864 100%) !important;\n  padding: 140px 24px 100px !important;\n  position: relative !important;\n  overflow: hidden !important;\n}\n\n/* ::after = grain texture + radial glow (combined) */\n.et_pb_section:has(.hero-inner)::after {\n  content: \'\' !important;\n  position: absolute !important;\n  inset: 0 !important;\n  background: radial-gradient(ellipse at 30% 50%, rgba(0,175,240,0.08), transparent 70%) !important;\n  pointer-events: none !important;\n  z-index: 1 !important;\n}\n\n.et_pb_section:has(.hero-inner) .et_pb_row {\n  max-width: 100% !important;\n  width: 100% !important;\n  padding: 0 !important;\n  position: static !important;\n}\n\n.et_pb_section:has(.hero-inner) .et_pb_column {\n  padding: 0 !important;\n  position: static !important;\n}\n\n.et_pb_section .hero-inner {\n  width: 100% !important;\n  -webkit-font-smoothing: auto !important;\n}\n\n/* Super D injected via JS as