ive;\n            z-index: 1;\n            margin-top: 4px;\n        }\n.featured-content {\n            padding: 48px;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n        }\n.event-type-badge {\n            display: inline-flex;\n            align-items: center;\n            padding: 6px 14px;\n            border-radius: 50px;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            font-weight: 500;\n            letter-spacing: 1px;\n            text-transform: uppercase;\n            margin-bottom: 16px;\n            width: fit-content;\n        }\n.event-type-badge.seminar {\n            background: rgba(0, 175, 240, 0.12);\n            color: #0369a1;\n        }\n.event-type-badge.workshop {\n            background: rgba(34, 197, 94, 0.12);\n            color: #15803d;\n        }\n.event-type-badge.factory-visit {\n            background: rgba(245, 158, 11, 0.12);\n            color: #b45309;\n        }\n.event-type-badge.trade-show {\n            background: rgba(139, 92, 246, 0.12);\n            color: #7c3aed;\n        }\n.featured-content h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 28px;\n            font-weight: 700;\n            color: #000864;\n            line-height: 1.3;\n            margin-bottom: 16px;\n        }\n.event-meta {\n            display: flex;\n            flex-direction: column;\n            gap: 8px;\n            margin-bottom: 20px;\n        }\n.event-meta-item {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n            font-size: 14px;\n            color: #5b6b80;\n        }\n.event-meta-item svg {\n            width: 16px;\n            height: 16px;\n            stroke: #00AFF0;\n            fill: none;\n            flex-shrink: 0;\n        }\n.featured-content p {\n            font-size: 15px;\n            color: #5b6b80;\n            line-height: 1.7;\