nd: #00AFF0; }\n.upc-card-border.workshop { background: #22C55E; }\n.upc-card-border.factory-visit { background: #F59E0B; }\n.upc-card-border.trade-show { background: #8B5CF6; }\n.upc-card-body {\n            padding: 32px;\n        }\n.upc-card-body .event-type-badge {\n            margin-bottom: 16px;\n        }\n.upc-card-body h3 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 20px;\n            font-weight: 600;\n            color: #000864;\n            line-height: 1.35;\n            margin-bottom: 16px;\n        }\n.upc-card-body .event-meta {\n            margin-bottom: 16px;\n        }\n.upc-card-body p {\n            font-size: 14px;\n            color: #5b6b80;\n            line-height: 1.6;\n            margin-bottom: 20px;\n        }\n.event-link {\n            display: inline-flex;\n            align-items: center;\n            gap: 6px;\n            color: #0369a1;\n            font-weight: 600;\n            font-size: 14px;\n            text-decoration: none;\n            transition: all 0.3s ease;\n        }\n.event-link:hover {\n            gap: 10px;\n        }\n.past-card .event-type-badge {\n            margin-bottom: 12px;\n        }\n.past-card .event-link {\n            font-size: 13px;\n        }\n.fade-in-section {\n            opacity: 0;\n            transform: translateY(30px);\n            transition: opacity 0.4s ease, transform 0.4s ease;\n        }\n.fade-in-section.is-visible {\n            opacity: 1;\n            transform: translateY(0);\n        }\n@media (max-width: 1024px) {\n.upc-grid {\n                grid-template-columns: repeat(2, 1fr);\n            }\n}\n@media (max-width: 640px) {\n.upc-grid {\n                grid-template-columns: 1fr;\n            }\n.upc-header h2,\n            .series-header h2,\n            .past-header h2 {\n                font-size: 28px;\n            }\n}\n\n/* === HOVER STATES (auto-ported from styles.css) === */\n.upc-card:hover{border-color:#00AFF0;box-shadow: