;padding:0;line-height:1.6}\n.section-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 12px;\n            font-weight: 500;\n            color: #0369a1;\n            letter-spacing: 2px;\n            text-transform: uppercase;\n            margin-bottom: 16px;\n            display: block;\n        }\n.series-section {\n            padding: 100px 24px;\n            background: #fff;\n        }\n.series-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n        }\n.series-header {\n            text-align: center;\n            margin-bottom: 64px;\n        }\n.series-header h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 40px;\n            font-weight: 700;\n            color: #000864;\n            margin-bottom: 16px;\n        }\n.series-header p {\n            font-size: 18px;\n            color: #5b6b80;\n            max-width: 650px;\n            margin: 0 auto;\n            line-height: 1.7;\n        }\n.series-timeline {\n            display: grid;\n            grid-template-columns: repeat(4, 1fr);\n            gap: 0;\n            position: relative;\n        }\n.series-timeline::before {\n            content: \'\';\n            position: absolute;\n            top: 32px;\n            left: 12.5%;\n            right: 12.5%;\n            height: 3px;\n            background: linear-gradient(90deg, #00AFF0, #22C55E, #F59E0B, #8B5CF6);\n            border-radius: 2px;\n            z-index: 0;\n        }\n.series-step {\n            text-align: center;\n            position: relative;\n            z-index: 1;\n            padding: 0 16px;\n        }\n.series-step-number {\n            width: 64px;\n            height: 64px;\n            border-radius: 50%;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            margin: 0 auto 20px;\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 22px;\n   